// Parse the Claude response and structure it properly
const apiResponse = $input.first().json;
const executionId = $execution.id || 'unknown';
const currentNode = 'Parse & Validate Response';

try {
  // Extract text from Anthropic API response
  let content = apiResponse.content?.[0]?.text || '';

  if (!content) {
    throw new Error('No content in API response');
  }

  // Remove any markdown code blocks if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse JSON response from Claude
  const parsed = JSON.parse(content);

  // Validate response structure
  if (typeof parsed.needs_clarification !== 'boolean') {
    throw new Error('Invalid response: missing needs_clarification');
  }

  // If clarification needed, validate questions
  if (parsed.needs_clarification) {
    if (!Array.isArray(parsed.questions) || parsed.questions.length === 0) {
      throw new Error('Invalid response: needs_clarification=true but no questions provided');
    }

    // Validate each question
    for (const q of parsed.questions) {
      if (!q.id || !q.question || !q.type) {
        throw new Error('Invalid question structure: missing id, question, or type');
      }

      if (!['choice', 'text', 'yes_no', 'number'].includes(q.type)) {
        throw new Error(`Invalid question type: ${q.type}`);
      }

      if ((q.type === 'choice' || q.type === 'yes_no') && !Array.isArray(q.options)) {
        throw new Error(`${q.type} question must have options array`);
      }

      if ((q.type === 'text' || q.type === 'number') && q.options) {
        throw new Error(`${q.type} question should not have options array`);
      }
    }

    // Limit to 3 questions max
    if (parsed.questions.length > 3) {
      parsed.questions = parsed.questions.slice(0, 3);
    }
  }

  // Validate pre_analysis_context (should always be present now)
  // If needs_clarification=true, context may be null (will be built from answers)
  // If needs_clarification=false, context should be present (inferred)
  if (!parsed.needs_clarification && !parsed.pre_analysis_context) {
    console.warn('Warning: needs_clarification=false but no pre_analysis_context provided');
    // Don't fail - just log warning and proceed
  }

  // Extract API usage data
  const apiUsage = {
    model: apiResponse.model || 'claude-3-5-haiku-20241022',
    input_tokens: apiResponse.usage?.input_tokens || 0,
    output_tokens: apiResponse.usage?.output_tokens || 0
  };

  // Return structured response
  return {
    json: {
      success: true,
      data: {
        needs_clarification: parsed.needs_clarification,
        questions: parsed.questions || null,
        pre_analysis_context: parsed.pre_analysis_context || null,
        reasoning: parsed.reasoning || (parsed.needs_clarification ? 
          'These questions will help optimise your prompt.' : 
          'Your task description is clear.')
      },
      api_usage: apiUsage
    }
  };

} catch (error) {
  // On any error, gracefully skip pre-analysis
  console.error('Pre-analysis parsing error:', error.message);

  // Determine error type and failed node
  const errorType = error.message.includes('No content') ? 'api_error' : 'parsing_error';
  const failedNode = error.message.includes('No content') ? 'Call Anthropic API' : currentNode;

  return {
    json: {
      success: true,
      data: {
        needs_clarification: false,
        pre_analysis_context: null,
        reasoning: 'Proceeding directly to analysis.'
      },
      api_usage: null,
      error_context: {
        error_type: errorType,
        failed_node: failedNode,
        execution_id: executionId,
        timestamp: new Date().toISOString(),
        gracefully_skipped: true
      }
    }
  };
}
